import { loadPicture } from './module/photoloader';
import { Photo } from './module/types';

function getPicture(id: number): void {
    loadPicture(id)
        .then((data: Photo) => {
            console.log("Titre :", data.photo.titre);
            console.log("Type :", data.type);
            console.log("URL :", data.photo.url);
        })
        .catch(err => console.error(err.message));
}

const hash = window.location.hash;
const idFromHash = hash ? parseInt(hash.substring(1)) : 105

getPicture(idFromHash);